class Solution(object):
    def countValidSelections(self, nums):
        total = sum(nums)
        count = 0
        prefix = 0
        for x in nums:
            if x == 0:
                suffix = total - prefix
                if prefix == suffix:
                    count += 2
            else:
                prefix += x
        return count
